def add(a, b):
    return a+b
def sub(a,b):
    return a-b
def multi(a, b):
    return a*b
def div(a, b):
    return a/b
print("the addition of two number is",add(2,5))
print("the subraction of two numbers is", sub(10, 5))
print("the multiplication of two numbers is", multi(2,5))
print("the division of two numbers is", div(10, 5))
